final:
module top_module (
    input d,
    input i,
    input f,
    output reg k
);
    always @(*) begin
        case ({d, i, f})
            3'b101: k = 1'b1;
            3'b100: k = 1'b0;
            3'b111: k = 1'b1;
            3'b001: k = 1'b0;
            3'b010: k = 1'b1;
            3'b000: k = 1'b0;
            3'b011: k = 1'b0;
            3'b110: k = 1'b1;
        endcase
    end
endmodule
